  1→/**
  2→ * Observer LLM Reasoning Acceptance Test Kit
  3→ *
  4→ * Extends the observer-test-kit with LLM reasoning-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Key difference from observer-agent tests: these tests exercise real LLM calls
  8→ * via the configured OBSERVER_MODEL. No mocking of LLM responses.
  9→ *
 10→ * Driving ports:
 11→ *   POST /api/observe/:table/:id         (SurrealQL EVENT target)
 12→ *   POST /api/observe/scan/:workspaceId  (periodic graph scan)
 13→ *   SurrealDB direct queries             (verification of outcomes)
 14→ */
 15→import { RecordId, type Surreal } from "surrealdb";
 16→
 17→// Re-export everything from observer-test-kit
 18→export {
 19→  setupObserverSuite,
 20→  wireObserverEvents,
 21→  setupObserverWorkspace,
 22→  createTaskWithCommit,
 23→  createGitCommit,
 24→  createCompletedIntent,
 25→  createObservationByAgent,
 26→  createConfirmedDecision,
 27→  triggerTaskCompletion,
 28→  triggerIntentCompletion,
 29→  triggerDecisionConfirmation,
 30→  waitForObservation,
 31→  getObservationsForEntity,
 32→  getWorkspaceObservations,
 33→  triggerGraphScan,
 34→  createMockGitHubServer,
 35→  type ObservationRecord,
 36→  type ObservationSeverity,
 37→  type ObservationStatus,
 38→  type ObservationType,
 39→} from "../observer-agent/observer-test-kit";
 40→
 41→import {
 42→  waitForObservation,
 43→  getObservationsForEntity,
 44→  getWorkspaceObservations,
 45→  type ObservationRecord,
 46→} from "../observer-agent/observer-test-kit";
 47→
 48→// ---------------------------------------------------------------------------
 49→// LLM Reasoning-Specific Types
 50→// ---------------------------------------------------------------------------
 51→
 52→export type LlmObservationRecord = ObservationRecord & {
 53→  confidence?: number;
 54→  evidence_refs?: RecordId[];
 55→};
 56→
 57→// ---------------------------------------------------------------------------
 58→// LLM Reasoning-Specific Helpers
 59→// ---------------------------------------------------------------------------
 60→
 61→/**
 62→ * Creates a confirmed decision linked to a project in the graph.
 63→ * Used to set up semantic contradiction scenarios where the LLM
 64→ * evaluates task alignment against decision text.
 65→ */
 66→export async function createDecisionInProject(
 67→  surreal: Surreal,
 68→  workspaceId: string,
 69→  projectId: string,
 70→  opts: {
 71→    summary: string;
 72→    rationale?: string;
 73→    status?: string;
 74→  },
 75→): Promise<{ decisionId: string }> {
 76→  const decisionId = `dec-${crypto.randomUUID()}`;
 77→  const decisionRecord = new RecordId("decision", decisionId);
 78→  const workspaceRecord = new RecordId("workspace", workspaceId);
 79→  const projectRecord = new RecordId("project", projectId);
 80→
 81→  await surreal.query(`CREATE $dec CONTENT $content;`, {
 82→    dec: decisionRecord,
 83→    content: {
 84→      summary: opts.summary,
 85→      rationale: opts.rationale ?? "Confirmed for testing",
 86→      status: opts.status ?? "confirmed",
 87→      workspace: workspaceRecord,
 88→      created_at: new Date(),
 89→      updated_at: new Date(),
 90→    },
 91→  });
 92→
 93→  // Link decision to project
 94→  await surreal.query(
 95→    `RELATE $dec->belongs_to->$project SET added_at = time::now();`,
 96→    { dec: decisionRecord, project: projectRecord },
 97→  );
 98→
 99→  return { decisionId };
100→}
101→
102→/**
103→ * Creates a project in the workspace.
104→ */
105→export async function createProject(
106→  surreal: Surreal,
107→  workspaceId: string,
108→  name: string,
109→): Promise<{ projectId: string }> {
110→  const projectId = `proj-${crypto.randomUUID()}`;
111→  const projectRecord = new RecordId("project", projectId);
112→  const workspaceRecord = new RecordId("workspace", workspaceId);
113→
114→  await surreal.query(`CREATE $proj CONTENT $content;`, {
115→    proj: projectRecord,
116→    content: {
117→      name,
118→      status: "active",
119→      workspace: workspaceRecord,
120→      created_at: new Date(),
121→      updated_at: new Date(),
122→    },
123→  });
124→
125→  return { projectId };
126→}
