128→/**
129→ * Creates a task linked to a project (and optionally a commit) in the graph.
130→ * Used to set up scenarios where the LLM evaluates task alignment against decisions.
131→ */
132→export async function createTaskInProject(
133→  surreal: Surreal,
134→  workspaceId: string,
135→  projectId: string,
136→  opts: {
137→    title: string;
138→    description?: string;
139→    status?: string;
140→  },
141→): Promise<{ taskId: string }> {
142→  const taskId = `task-${crypto.randomUUID()}`;
143→  const taskRecord = new RecordId("task", taskId);
144→  const workspaceRecord = new RecordId("workspace", workspaceId);
145→  const projectRecord = new RecordId("project", projectId);
146→
147→  await surreal.query(`CREATE $task CONTENT $content;`, {
148→    task: taskRecord,
149→    content: {
150→      title: opts.title,
151→      description: opts.description ?? "Test task for LLM reasoning",
152→      status: opts.status ?? "in_progress",
153→      workspace: workspaceRecord,
154→      created_at: new Date(),
155→      updated_at: new Date(),
156→    },
157→  });
158→
159→  // Link task to project
160→  await surreal.query(
161→    `RELATE $task->belongs_to->$project SET added_at = time::now();`,
162→    { task: taskRecord, project: projectRecord },
163→  );
164→
165→  return { taskId };
166→}
