168→/**
169→ * Sets workspace settings for observer skip optimization.
170→ */
171→export async function setWorkspaceObserverSkip(
172→  surreal: Surreal,
173→  workspaceId: string,
174→  skipDeterministic: boolean,
175→): Promise<void> {
176→  const workspaceRecord = new RecordId("workspace", workspaceId);
177→  await surreal.query(
178→    `UPDATE $ws SET settings = { observer_skip_deterministic: $skip };`,
179→    { ws: workspaceRecord, skip: skipDeterministic },
180→  );
181→}
182→
183→/**
184→ * Waits for an observation with a specific source (e.g. "llm", "deterministic_fallback").
185→ * Useful when multiple observations may exist for an entity.
186→ */
187→export async function waitForObservationWithSource(
188→  surreal: Surreal,
189→  entityTable: string,
190→  entityId: string,
191→  source: string,
192→  timeoutMs = 30_000,
193→): Promise<LlmObservationRecord[]> {
194→  const start = Date.now();
195→
196→  while (Date.now() - start < timeoutMs) {
197→    const observations = await getObservationsForEntity(surreal, entityTable, entityId);
198→    const matching = observations.filter((o) => o.source === source);
199→    if (matching.length > 0) {
200→      return matching as LlmObservationRecord[];
201→    }
202→    await Bun.sleep(500);
203→  }
204→
205→  throw new Error(
206→    `No observation with source="${source}" found for ${entityTable}:${entityId} within ${timeoutMs}ms`,
207→  );
208→}
209→
210→/**
211→ * Waits for an observation of a specific type linked to an entity.
212→ */
213→export async function waitForObservationOfType(
214→  surreal: Surreal,
215→  entityTable: string,
216→  entityId: string,
217→  observationType: string,
218→  timeoutMs = 30_000,
219→): Promise<LlmObservationRecord[]> {
220→  const start = Date.now();
221→
222→  while (Date.now() - start < timeoutMs) {
223→    const observations = await getObservationsForEntity(surreal, entityTable, entityId);
224→    const matching = observations.filter((o) => o.observation_type === observationType);
225→    if (matching.length > 0) {
226→      return matching as LlmObservationRecord[];
227→    }
228→    await Bun.sleep(500);
229→  }
230→
231→  throw new Error(
232→    `No observation with type="${observationType}" found for ${entityTable}:${entityId} within ${timeoutMs}ms`,
233→  );
234→}
235→
236→/**
237→ * Gets all observes edges from a specific observation.
238→ * Returns the target entity record IDs.
239→ */
240→export async function getObservesTargets(
241→  surreal: Surreal,
242→  observationId: string,
243→): Promise<RecordId[]> {
244→  const obsRecord = new RecordId("observation", observationId);
245→
246→  const rows = (await surreal.query(
247→    `SELECT ->observes->? AS targets FROM $obs;`,
248→    { obs: obsRecord },
249→  )) as Array<Array<{ targets: RecordId[] }>>;
250→
251→  return rows[0]?.[0]?.targets ?? [];
252→}
253→
254→/**
255→ * Counts observations matching criteria in a workspace.
256→ * Useful for verifying deduplication and count assertions.
257→ */
258→export async function countObservations(
259→  surreal: Surreal,
260→  workspaceId: string,
261→  filters: {
262→    observationType?: string;
263→    sourceAgent?: string;
264→    source?: string;
265→    status?: string;
266→  },
267→): Promise<number> {
268→  const wsRecord = new RecordId("workspace", workspaceId);
269→  let query = `SELECT count() AS count FROM observation WHERE workspace = $ws`;
270→  const params: Record<string, unknown> = { ws: wsRecord };
271→
272→  if (filters.observationType) {
273→    query += ` AND observation_type = $obsType`;
274→    params.obsType = filters.observationType;
275→  }
276→  if (filters.sourceAgent) {
277→    query += ` AND source_agent = $agent`;
278→    params.agent = filters.sourceAgent;
279→  }
280→  if (filters.source) {
281→    query += ` AND source = $source`;
282→    params.source = filters.source;
283→  }
284→  if (filters.status) {
285→    query += ` AND status = $status`;
286→    params.status = filters.status;
287→  }
288→
289→  query += ` GROUP ALL;`;
290→
291→  const rows = (await surreal.query(query, params)) as Array<Array<{ count: number }>>;
292→  return rows[0]?.[0]?.count ?? 0;
293→}
